# Barrier analysis: process survey responses and compute barrier prevalence scores

from dataclasses import dataclass
from collections import defaultdict
import statistics

BARRIER_CATEGORIES = [
    "awareness",
    "access",
    "skill",
    "trust",
    "relevance",
    "organisational",
]

@dataclass
class BarrierSurveyResponse:
    respondent_id: str
    role_category: str
    business_unit: str
    funnel_stage: str   # "aware" | "trial" | "activated" | "regular"
    barrier_scores: dict[str, int]   # category → 1-5 rating
    top_priority_barrier: str        # which one they most want addressed

def compute_barrier_prevalence(
    responses: list[BarrierSurveyResponse],
    significant_threshold: int = 4,   # 4 or 5 on 5-pt scale = significant
) -> dict[str, dict]:
    """
    Returns prevalence (% citing as significant) and average score per barrier category.
    Also breaks down by role and business unit.
    """
    results = {}
    for cat in BARRIER_CATEGORIES:
        scores = [r.barrier_scores.get(cat, 0) for r in responses]
        significant = sum(1 for s in scores if s >= significant_threshold)
        results[cat] = {
            "avg_score": round(statistics.mean(scores), 2) if scores else 0,
            "prevalence_pct": round(significant / len(scores) * 100, 1) if scores else 0,
            "priority_votes": sum(1 for r in responses if r.top_priority_barrier == cat),
        }
    return results

def barrier_by_segment(
    responses: list[BarrierSurveyResponse],
    segment_key: str = "role_category",
) -> dict[str, dict]:
    """Compute barrier prevalence segmented by a demographic attribute."""
    by_segment: dict[str, list] = defaultdict(list)
    for r in responses:
        by_segment[getattr(r, segment_key)].append(r)
    return {
        seg: compute_barrier_prevalence(seg_responses)
        for seg, seg_responses in by_segment.items()
    }

# Barrier priority matrix: rank barriers by (prevalence × tractability) score

from dataclasses import dataclass

@dataclass
class BarrierAssessment:
    category: str
    prevalence_pct: float     # from survey: 0-100
    tractability_score: int   # programme team judgement: 1-5 (5=most tractable)
    authority_required: str   # "programme_team" | "business_unit_leader" | "executive"
    notes: str = ""

    def priority_score(self) -> float:
        return round((self.prevalence_pct / 100) * self.tractability_score, 2)

def rank_barriers(assessments: list[BarrierAssessment]) -> list[dict]:
    ranked = sorted(assessments, key=lambda a: a.priority_score(), reverse=True)
    return [
        {
            "rank": i + 1,
            "category": a.category,
            "prevalence_pct": a.prevalence_pct,
            "tractability": a.tractability_score,
            "priority_score": a.priority_score(),
            "authority": a.authority_required,
        }
        for i, a in enumerate(ranked)
    ]

# Example
barriers = [
    BarrierAssessment("skill", 68.0, 5, "programme_team", "Structured onboarding addresses this"),
    BarrierAssessment("trust", 54.0, 3, "programme_team", "Use-case validation demos help"),
    BarrierAssessment("organisational", 47.0, 2, "executive", "Manager resistance; needs senior intervention"),
    BarrierAssessment("access", 31.0, 4, "business_unit_leader", "IT provisioning backlog"),
    BarrierAssessment("relevance", 28.0, 2, "programme_team", "Role-specific use cases needed"),
    BarrierAssessment("awareness", 19.0, 5, "programme_team", "Communications gap; easy to close"),
]
for b in rank_barriers(barriers):
    print(b)
